{%- assign phone_number = "+33767422570" -%}
<div class="phone-banner-compact">
  <div class="phone-banner-compact__wrapper">
    <div class="phone-banner-compact__info">
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
        <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"></path>
      </svg>
      <div>
        <span class="phone-banner-compact__label">Besoin d'un aperçu du volant ?</span>
        <a href="tel:{{ phone_number }}" class="phone-banner-compact__number">{{ phone_number }}</a>
      </div>
    </div>
    <button class="phone-banner-compact__copy js-copy-phone-compact" title="Copier le numéro">
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
        <rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect>
        <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path>
      </svg>
    </button>
  </div>
</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
  const copyBtn = document.querySelector('.js-copy-phone-compact');
  if (copyBtn) {
    copyBtn.addEventListener('click', function() {
      navigator.clipboard.writeText('{{ phone_number }}').then(function() {
        const originalHTML = copyBtn.innerHTML;
        copyBtn.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M20 6L9 17l-5-5"></path></svg>';
        copyBtn.classList.add('copied');
        setTimeout(function() {
          copyBtn.innerHTML = originalHTML;
          copyBtn.classList.remove('copied');
        }, 2000);
      });
    });
  }
});
</script>

<style>
.phone-banner-compact {
  width: 100%;
  max-width: 500px;
  margin: 1.5rem auto;
}

.phone-banner-compact__wrapper {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 1rem 1.25rem;
  background: linear-gradient(45deg, #1e3a8a, #3b82f6, #1e3a8a, #3b82f6);
  background-size: 300% 300%;
  animation: gradient-shift 4s ease infinite;
  border-radius: 12px;
  box-shadow: 0 4px 12px rgba(30, 58, 138, 0.25);
}

.phone-banner-compact__info {
  display: flex;
  align-items: center;
  gap: 0.875rem;
  color: white;
}

.phone-banner-compact__info > svg {
  flex-shrink: 0;
}

.phone-banner-compact__label {
  display: block;
  font-size: 0.9rem;
  color: #e0e7ff;
  font-weight: 600;
  margin-bottom: 0.25rem;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
}

.phone-banner-compact__number {
  display: block;
  font-size: 1.25rem;
  font-weight: 700;
  color: white;
  text-decoration: none;
  letter-spacing: 0.025em;
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.15);
}

.phone-banner-compact__number:hover {
  text-decoration: underline;
}

.phone-banner-compact__copy {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  background: rgba(255, 255, 255, 0.2);
  border: none;
  border-radius: 8px;
  color: white;
  cursor: pointer;
  transition: all 0.2s ease;
  backdrop-filter: blur(10px);
}

.phone-banner-compact__copy:hover {
  background: rgba(255, 255, 255, 0.3);
  transform: scale(1.05);
}

.phone-banner-compact__copy.copied {
  background: rgba(16, 185, 129, 0.9);
}

@media screen and (max-width: 640px) {
  .phone-banner-compact {
    margin: 1rem auto;
  }

  .phone-banner-compact__wrapper {
    padding: 0.875rem 1rem;
  }

  .phone-banner-compact__label {
    font-size: 0.85rem;
  }

  .phone-banner-compact__number {
    font-size: 1.125rem;
  }
}
</style>

{%- comment -%}
  Clickroad — Stories Instagram-like
  Plusieurs vidéos par story, séparées par "|" dans story_X_urls
  Barre de progression par vidéo (style Instagram)
  Son activé, pause, fermeture, auto-avance fonctionnels iOS/Safari
{%- endcomment -%}

{%- comment -%} URLs de chaque story : vidéos séparées par "|" {%- endcomment -%}
{%- assign s1_urls = story_1_urls | default: "https://cdn.shopify.com/videos/c/o/v/e792a03228534475878b22d492a8f6c7.mp4|https://cdn.shopify.com/videos/c/o/v/220b4ed5b7394775aea6ad714eee156b.mp4" -%}
{%- assign s1_txt  = story_1_text  | default: "Story 1" -%}
{%- assign s2_urls = story_2_urls  | default: "https://cdn.shopify.com/videos/c/o/v/220b4ed5b7394775aea6ad714eee156b.mp4|https://cdn.shopify.com/videos/c/o/v/e792a03228534475878b22d492a8f6c7.mp4" -%}
{%- assign s2_txt  = story_2_text  | default: "Nouveautés" -%}
{%- assign s3_urls = story_3_urls  | default: "https://cdn.shopify.com/videos/c/o/v/e792a03228534475878b22d492a8f6c7.mp4" -%}
{%- assign s3_txt  = story_3_text  | default: "Promo" -%}
{%- assign s4_urls = story_4_urls  | default: "" -%}
{%- assign s4_txt  = story_4_text  | default: "" -%}
{%- assign s5_urls = story_5_urls  | default: "" -%}
{%- assign s5_txt  = story_5_text  | default: "" -%}
{%- assign s6_urls = story_6_urls  | default: "" -%}
{%- assign s6_txt  = story_6_text  | default: "" -%}
{%- assign s7_urls = story_7_urls  | default: "" -%}
{%- assign s7_txt  = story_7_text  | default: "" -%}
{%- assign s8_urls = story_8_urls  | default: "" -%}
{%- assign s8_txt  = story_8_text  | default: "" -%}

{%- assign all_groups = s1_urls | append: "@@" | append: s2_urls | append: "@@" | append: s3_urls | append: "@@" | append: s4_urls | append: "@@" | append: s5_urls | append: "@@" | append: s6_urls | append: "@@" | append: s7_urls | append: "@@" | append: s8_urls -%}
{%- assign all_labels = s1_txt | append: "@@" | append: s2_txt | append: "@@" | append: s3_txt | append: "@@" | append: s4_txt | append: "@@" | append: s5_txt | append: "@@" | append: s6_txt | append: "@@" | append: s7_txt | append: "@@" | append: s8_txt -%}
{%- assign groups_arr = all_groups | split: "@@" -%}
{%- assign labels_arr = all_labels | split: "@@" -%}

{%- assign _align = alignment | default: "center" -%}
{%- case _align -%}
  {%- when "left" -%}  {%- assign _justify = "flex-start" -%}
  {%- when "right" -%} {%- assign _justify = "flex-end" -%}
  {%- else -%}         {%- assign _justify = "center" -%}
{%- endcase -%}
{%- if stories_shape == "square" -%}{%- assign _radius = "12px" -%}{%- else -%}{%- assign _radius = "50%" -%}{%- endif -%}

<div class="crStories9" data-cr-stories
  style="
    --crs-pad:          {{ container_padding | default: '0px 10px' }};
    --crs-gap:          {{ stories_gap       | default: '12px' }};
    --crs-mt:           {{ margin_top        | default: '20px' }};
    --crs-mb:           {{ margin_bottom     | default: '20px' }};
    --crs-size:         {{ circle_size       | default: '82px' }};
    --crs-radius:       {{ _radius }};
    --crs-border:       {{ border_size       | default: '3px' }};
    --crs-border-color: {{ border_color      | default: '#e1306c' }};
    --crs-justify:      {{ _justify }};
    --crs-text-size:    {{ text_size         | default: '12px' }};
    --crs-label-color:  {{ label_color       | default: '#111111' }};
    --crs-label-weight: {{ label_weight      | default: '500' }};
  "
>
  <!-- ── Miniatures ── -->
  <div class="crStories9__row">
    {%- for grp in groups_arr -%}
      {%- assign grp_clean = grp | strip -%}
      {%- if grp_clean != blank -%}
        {%- assign grp_idx   = forloop.index0 -%}
        {%- assign lbl       = labels_arr[grp_idx] | strip -%}
        {%- assign first_url = grp_clean | split: "|" | first -%}
        <div class="crStories9__item">
          <button class="crStories9__circle" type="button" data-crs-open="{{ grp_idx }}" aria-label="Ouvrir story {{ grp_idx | plus: 1 }}">
            <span class="crStories9__icon" aria-hidden="true">
              <svg viewBox="0 0 24 24"><path d="M8 5v14l12-7-12-7z"/></svg>
            </span>
            <video class="crStories9__thumb" muted playsinline loop preload="metadata" loading="lazy" aria-hidden="true">
              <source src="{{ first_url }}" type="video/mp4">
            </video>
          </button>
          {%- if lbl != blank -%}
            <div class="crStories9__label">{{ lbl | escape }}</div>
          {%- endif -%}
        </div>
      {%- endif -%}
    {%- endfor -%}
  </div>

  <!-- ── Modal ── -->
  <div class="crStories9__modal" hidden data-crs-modal>
    <div class="crStories9__backdrop" data-crs-backdrop></div>
    <div class="crStories9__stage" role="dialog" aria-modal="true" aria-label="Story">

      <!-- Barres de progression (générées dynamiquement en JS) -->
      <div class="crStories9__bars" data-crs-bars></div>

      <!-- Boutons haut -->
      <div class="crStories9__topBtns">
        <button class="crStories9__iconBtn crs-toggle-play" type="button" aria-label="Pause / Play">
          <span class="crsPlayIcon" aria-hidden="true">
            <svg viewBox="0 0 24 24"><path d="M8 5v14l12-7-12-7z"/></svg>
          </span>
          <span class="crsPauseIcon" aria-hidden="true" style="display:none;">
            <svg viewBox="0 0 24 24"><path d="M6 5h4v14H6V5zm8 0h4v14h-4V5z"/></svg>
          </span>
        </button>

        <button class="crStories9__iconBtn crs-toggle-mute" type="button" aria-label="Son / Muet">
          <span class="crsSoundIcon" aria-hidden="true">
            <svg viewBox="0 0 24 24"><path d="M3 10v4h4l5 4V6L7 10H3zm13.5 2c0-1.77-1.02-3.29-2.5-4.03v8.06c1.48-.74 2.5-2.26 2.5-4.03zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/></svg>
          </span>
          <span class="crsMutedIcon" aria-hidden="true" style="display:none;">
            <svg viewBox="0 0 24 24"><path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v2.21l2.45 2.45c.03-.2.05-.63zM19 12c0 .94-.2 1.84-.56 2.66l1.51 1.51C20.63 14.97 21 13.53 21 12c0-3.28-1.97-6.1-4.8-7.35v2.2C17.93 7.88 19 9.84 19 12zM4.27 3L3 4.27l7 7V6L5 10H3v4h4l5 4v-5.73l5.73 5.73 1.27-1.27L4.27 3z"/></svg>
          </span>
        </button>

        <button class="crStories9__iconBtn crStories9__closeBtn" type="button" data-crs-close aria-label="Fermer">
          <svg viewBox="0 0 24 24"><path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z"/></svg>
        </button>
      </div>

      <!-- Navigation story précédente / suivante -->
      <button class="crStories9__nav crStories9__navPrev" type="button" data-crs-prev aria-label="Story précédente">
        <svg viewBox="0 0 24 24"><path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/></svg>
      </button>
      <button class="crStories9__nav crStories9__navNext" type="button" data-crs-next aria-label="Story suivante">
        <svg viewBox="0 0 24 24"><path d="M8.59 16.59L10 18l6-6-6-6-1.41 1.41L13.17 12z"/></svg>
      </button>

      <video class="crStories9__bigVid" data-crs-big playsinline preload="auto" aria-label="Story vidéo"></video>
      <div class="crStories9__loading" aria-live="polite">Chargement…</div>
      <button class="crStories9__playFallback" type="button" hidden aria-label="Démarrer la vidéo">&#9654; Play</button>
    </div>
  </div>

  {% style %}
  .crStories9 { width:100%; padding:var(--crs-pad); margin:var(--crs-mt) 0 var(--crs-mb); }

  /* ── Ligne miniatures ── */
  .crStories9__row {
    display:flex; gap:var(--crs-gap); justify-content:var(--crs-justify);
    align-items:flex-start; overflow-x:auto; -webkit-overflow-scrolling:touch;
    padding-bottom:10px; scrollbar-width:thin;
  }
  .crStories9__row::-webkit-scrollbar { height:6px; }
  .crStories9__row::-webkit-scrollbar-thumb { background:rgba(100,100,100,.4); border-radius:3px; }
  .crStories9__item {
    flex:0 0 auto; display:flex; flex-direction:column;
    align-items:center; gap:8px; min-width:calc(var(--crs-size) + 20px);
  }
  .crStories9__circle {
    position:relative; width:var(--crs-size); height:var(--crs-size);
    border-radius:var(--crs-radius); border:var(--crs-border) solid var(--crs-border-color);
    background:#000; display:flex; align-items:center; justify-content:center;
    cursor:pointer; padding:0; overflow:hidden; transition:border-color .2s;
    -webkit-tap-highlight-color:transparent;
  }
  .crStories9__circle:hover { border-color:#fff; }
  .crStories9__thumb {
    position:absolute; inset:0; width:100%; height:100%;
    object-fit:cover; pointer-events:none; opacity:.92;
  }
  .crStories9__icon {
    width:30px; height:30px; color:#fff; z-index:2;
    filter:drop-shadow(0 2px 6px rgba(0,0,0,.6)); position:absolute;
  }
  .crStories9__icon svg { width:100%; height:100%; fill:currentColor; }
  .crStories9__label {
    font-size:var(--crs-text-size); font-weight:var(--crs-label-weight);
    color:var(--crs-label-color); text-align:center; line-height:1.3;
    max-width:calc(var(--crs-size) + 30px); word-break:break-word;
    overflow:hidden; text-overflow:ellipsis;
    display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical;
  }

  /* ── Modal ── */
  .crStories9__modal {
    position:fixed; inset:0; z-index:9999;
    display:flex; align-items:center; justify-content:center;
    padding:12px; background:rgba(0,0,0,.92);
  }
  .crStories9__modal[hidden] { display:none !important; }
  .crStories9__backdrop { position:absolute; inset:0; cursor:pointer; }

  /* ── Scène ── */
  .crStories9__stage {
    position:relative; width:100%; max-width:420px;
    aspect-ratio:9/16; background:#000; border-radius:16px;
    overflow:hidden; box-shadow:0 10px 50px rgba(0,0,0,.7); pointer-events:auto;
  }
  .crStories9__bigVid { width:100%; height:100%; object-fit:contain; display:block; }

  /* ── Barres de progression style Instagram ── */
  .crStories9__bars {
    position:absolute; top:10px; left:10px; right:10px;
    display:flex; gap:4px; z-index:20;
    pointer-events:none;
  }
  .crStories9__bar {
    flex:1; height:3px; background:rgba(255,255,255,.35);
    border-radius:2px; overflow:hidden;
  }
  .crStories9__barFill {
    height:100%; width:0%; background:#fff; border-radius:2px;
  }
  .crStories9__bar.is-done .crStories9__barFill { width:100%; }

  /* ── Boutons haut ── */
  .crStories9__topBtns {
    position:absolute; top:22px; right:10px;
    display:flex; align-items:center; gap:6px; z-index:30;
  }
  .crStories9__iconBtn {
    width:36px; height:36px; border:none; border-radius:50%;
    background:rgba(0,0,0,.45); color:#fff; cursor:pointer;
    display:flex; align-items:center; justify-content:center;
    pointer-events:auto; flex-shrink:0;
    -webkit-tap-highlight-color:transparent; touch-action:manipulation;
  }
  .crStories9__iconBtn svg { width:20px; height:20px; fill:currentColor; }
  .crStories9__closeBtn { z-index:50 !important; }

  /* ── Navigation ── */
  .crStories9__nav {
    position:absolute; top:50%; transform:translateY(-50%);
    z-index:25; width:40px; height:60px;
    background:rgba(0,0,0,.3); border:none; color:#fff;
    cursor:pointer; display:flex; align-items:center; justify-content:center;
    -webkit-tap-highlight-color:transparent;
  }
  .crStories9__nav svg { width:24px; height:24px; fill:currentColor; }
  .crStories9__navPrev { left:0; border-radius:0 8px 8px 0; }
  .crStories9__navNext { right:0; border-radius:8px 0 0 8px; }

  /* ── Chargement ── */
  .crStories9__loading {
    position:absolute; inset:0; display:flex; align-items:center;
    justify-content:center; color:#fff; font-size:1.4rem;
    background:rgba(0,0,0,.5); pointer-events:none; z-index:10;
  }
  .crStories9__loading.is-hidden { display:none; }

  /* ── Fallback play ── */
  .crStories9__playFallback {
    position:absolute; inset:0; margin:auto;
    width:80px; height:80px; border:none; border-radius:50%;
    background:rgba(255,255,255,.3); color:#fff; font-size:2.5rem;
    cursor:pointer; z-index:15;
    display:flex; align-items:center; justify-content:center;
  }
  .crStories9__playFallback[hidden] { display:none; }

  /* Masque contrôles natifs Safari */
  video::-webkit-media-controls,
  video::-webkit-media-controls-enclosure { display:none !important; }
  {% endstyle %}

  <script>
  (function () {
    'use strict';

    /* ── Données injectées par Liquid ──
       storiesData[i] = tableau d'URLs vidéos de la story i
    ─────────────────────────────────── */
    var rawGroups  = {{ groups_arr | json }};
    var storiesData = rawGroups
      .map(function (g) { return (g || '').trim(); })
      .filter(function (g) { return g !== ''; })
      .map(function (g) {
        return g.split('|').map(function (u) { return u.trim(); }).filter(function (u) { return u !== ''; });
      });

    /* ── Références DOM ── */
    var modal         = document.querySelector('[data-crs-modal]');
    var stage         = document.querySelector('.crStories9__stage');
    var bigVid        = document.querySelector('[data-crs-big]');
    var loading       = document.querySelector('.crStories9__loading');
    var playFallback  = document.querySelector('.crStories9__playFallback');
    var btnPlay       = document.querySelector('.crs-toggle-play');
    var btnMute       = document.querySelector('.crs-toggle-mute');
    var playIcon      = btnPlay && btnPlay.querySelector('.crsPlayIcon');
    var pauseIcon     = btnPlay && btnPlay.querySelector('.crsPauseIcon');
    var soundIcon     = btnMute && btnMute.querySelector('.crsSoundIcon');
    var mutedIcon     = btnMute && btnMute.querySelector('.crsMutedIcon');
    var backdrop      = document.querySelector('[data-crs-backdrop]');
    var barsContainer = document.querySelector('[data-crs-bars]');

    /* ── État ── */
    var currentStory = 0;
    var currentVid   = 0;
    var isMuted      = false;
    var rafId        = null;
    var barFills     = [];

    /* ════════════════════════════
       Barres de progression
    ════════════════════════════ */
    function buildBars(count) {
      barsContainer.innerHTML = '';
      barFills = [];
      for (var i = 0; i < count; i++) {
        var bar  = document.createElement('div');
        bar.className = 'crStories9__bar';
        var fill = document.createElement('div');
        fill.className = 'crStories9__barFill';
        bar.appendChild(fill);
        barsContainer.appendChild(bar);
        barFills.push(fill);
      }
    }

    function resetBars(activeIdx) {
      barFills.forEach(function (f, i) {
        var bar = f.parentElement;
        bar.classList.remove('is-done');
        f.style.width = '0%';
        if (i < activeIdx) bar.classList.add('is-done');
      });
    }

    function animateBars() {
      cancelAnimationFrame(rafId);
      (function tick() {
        if (!bigVid.paused && bigVid.duration > 0 && barFills[currentVid]) {
          barFills[currentVid].style.width = (bigVid.currentTime / bigVid.duration * 100) + '%';
        }
        rafId = requestAnimationFrame(tick);
      })();
    }

    function stopAnimateBars() { cancelAnimationFrame(rafId); }

    /* ════════════════════════════
       Icônes
    ════════════════════════════ */
    function updateIcons() {
      if (playIcon && pauseIcon) {
        playIcon.style.display  = bigVid.paused ? 'block' : 'none';
        pauseIcon.style.display = bigVid.paused ? 'none'  : 'block';
      }
      if (soundIcon && mutedIcon) {
        soundIcon.style.display = isMuted ? 'none'  : 'block';
        mutedIcon.style.display = isMuted ? 'block' : 'none';
      }
    }

    /* ════════════════════════════
       Lecture d'une vidéo
    ════════════════════════════ */
    function playVid(vidIdx) {
      var story = storiesData[currentStory];
      if (!story || vidIdx >= story.length) return;
      currentVid = vidIdx;
      var url = story[vidIdx];

      stopAnimateBars();
      bigVid.pause();
      bigVid.removeAttribute('src');
      bigVid.innerHTML = '';
      bigVid.playsInline = true;
      bigVid.muted  = false;
      bigVid.volume = 1;

      var src   = document.createElement('source');
      src.src   = url;
      src.type  = 'video/mp4';
      bigVid.appendChild(src);
      bigVid.load();

      stage.classList.remove('is-playing');
      loading.classList.remove('is-hidden');
      playFallback.hidden = true;
      resetBars(vidIdx);
      updateIcons();

      bigVid.addEventListener('canplay', function tryPlay() {
        bigVid.removeEventListener('canplay', tryPlay);
        bigVid.play()
          .then(function () {
            stage.classList.add('is-playing');
            loading.classList.add('is-hidden');
            animateBars();
            updateIcons();
          })
          .catch(function () {
            /* Son bloqué → muet puis réessaie */
            isMuted = true; bigVid.muted = true;
            bigVid.play()
              .then(function () {
                stage.classList.add('is-playing');
                loading.classList.add('is-hidden');
                animateBars();
                updateIcons();
              })
              .catch(function () {
                loading.classList.add('is-hidden');
                playFallback.hidden = false;
                updateIcons();
              });
          });
      });
    }

    /* ════════════════════════════
       Ouverture d'une story
    ════════════════════════════ */
    function openStory(idx) {
      var story = storiesData[idx];
      if (!story || story.length === 0) return;
      currentStory = idx;
      isMuted = false;
      buildBars(story.length);
      modal.hidden = false;
      playVid(0);
    }

    /* ════════════════════════════
       Fermeture
    ════════════════════════════ */
    function closeModal() {
      stopAnimateBars();
      bigVid.pause();
      bigVid.removeAttribute('src');
      bigVid.innerHTML = '';
      modal.hidden = true;
      stage.classList.remove('is-playing');
      playFallback.hidden = true;
      updateIcons();
    }

    /* ════════════════════════════
       Navigation
    ════════════════════════════ */
    function goNext() {
      var story = storiesData[currentStory];
      if (story && currentVid < story.length - 1) {
        /* Vidéo suivante dans la même story */
        playVid(currentVid + 1);
      } else if (currentStory + 1 < storiesData.length) {
        /* Story suivante */
        openStory(currentStory + 1);
      } else {
        closeModal();
      }
    }

    function goPrev() {
      if (currentVid > 0) {
        playVid(currentVid - 1);
      } else if (currentStory > 0) {
        openStory(currentStory - 1);
      }
    }

    /* ════════════════════════════
       Événements
    ════════════════════════════ */

    /* Ouverture miniatures */
    document.querySelectorAll('[data-crs-open]').forEach(function (btn) {
      btn.addEventListener('click', function (e) {
        e.preventDefault();
        openStory(parseInt(btn.dataset.crsOpen, 10));
      });
    });

    /* Fallback play */
    if (playFallback) {
      playFallback.addEventListener('click', function () {
        bigVid.muted = isMuted; bigVid.volume = 1;
        bigVid.play().then(function () {
          stage.classList.add('is-playing');
          playFallback.hidden = true;
          animateBars(); updateIcons();
        }).catch(function () {});
      });
    }

    /* Pause / Play */
    if (btnPlay) {
      function handlePlayToggle(e) {
        e.preventDefault(); e.stopPropagation();
        if (bigVid.paused) {
          bigVid.play().then(function () {
            stage.classList.add('is-playing');
            animateBars(); updateIcons();
          }).catch(function () {});
        } else {
          bigVid.pause();
          stopAnimateBars();
          stage.classList.remove('is-playing');
          updateIcons();
        }
      }
      btnPlay.addEventListener('click',      handlePlayToggle, { passive: false });
      btnPlay.addEventListener('touchstart', handlePlayToggle, { passive: false });
    }

    /* Son / Muet */
    if (btnMute) {
      function handleMuteToggle(e) {
        e.preventDefault(); e.stopPropagation();
        isMuted = !isMuted;
        bigVid.muted  = isMuted;
        bigVid.volume = isMuted ? 0 : 1;
        if (!isMuted && bigVid.paused) bigVid.play().catch(function () {});
        updateIcons();
      }
      btnMute.addEventListener('click',      handleMuteToggle, { passive: false });
      btnMute.addEventListener('touchstart', handleMuteToggle, { passive: false });
    }

    /* Fermer */
    document.querySelectorAll('[data-crs-close]').forEach(function (el) {
      el.addEventListener('click', function (e) { e.preventDefault(); e.stopPropagation(); closeModal(); });
    });
    if (backdrop) backdrop.addEventListener('click', closeModal);
    document.addEventListener('keydown', function (e) { if (e.key === 'Escape' && !modal.hidden) closeModal(); });

    /* Navigation */
    var btnNext = document.querySelector('[data-crs-next]');
    var btnPrev = document.querySelector('[data-crs-prev]');
    if (btnNext) btnNext.addEventListener('click', function (e) { e.stopPropagation(); goNext(); });
    if (btnPrev) btnPrev.addEventListener('click', function (e) { e.stopPropagation(); goPrev(); });

    /* Auto-avance à la fin d'une vidéo */
    bigVid.addEventListener('ended', function () {
      stopAnimateBars();
      if (barFills[currentVid]) {
        barFills[currentVid].style.width = '100%';
        barFills[currentVid].parentElement.classList.add('is-done');
      }
      goNext();
    });

    /* Sync icônes */
    bigVid.addEventListener('play',  updateIcons);
    bigVid.addEventListener('pause', updateIcons);

  })();
  </script>
</div>

